import { HIGHLIGHT_EFFECT_REGEX, UNHIGHLIGHT_EFFECT_REGEX, charttype, chartcategory } from '../../../core/main-zc-init';
import { TRANSPARENT, NONE } from '../../../core/zc-constants';
import { isBarChartType } from '../../events-utils';
import { getHoverGradients, isMultiColoring } from '../../../utils/colorutils';
import { pick, arrayIncludes } from '../../../utils/zcutils';
import { getChartTypeByIndex } from '../../../core/charttype-helpers';

// #ZC2641 removed patternIndex = point.seriesIndex
export function patternFillEffect(point, basecolor, patternIndex) {
    var renderer = this.renderer,
        rp = renderer.commonRendererProp().params,
        legendH = this.chart.legendHighlight,
        hasMultiColor = isMultiColoring(rp.commonPlotOptions, this.chart),
        { seriesIndex, paneid } = point,
        index = pick(patternIndex, hasMultiColor ? pick(point.categoryIndex, point.sortedItemIndex) : seriesIndex),
        cType_Obj = getChartTypeByIndex(this.chart, paneid, seriesIndex),
        cType = isBarChartType(cType_Obj.value) ? 'bar' : cType_Obj.name,
        getLegendHighlightEffect = legendH.getLegendHighlightEffect,
        highlightEffect = getLegendHighlightEffect && getLegendHighlightEffect(seriesIndex, 'selectedSeries', 'plot', paneid),
        unHighlightEffect = getLegendHighlightEffect && getLegendHighlightEffect(seriesIndex, 'unselectedSeries', 'plot', paneid),
        options = this.options(point),
        seriescolor = options.color,
        hasColor = HIGHLIGHT_EFFECT_REGEX.test(highlightEffect) || UNHIGHLIGHT_EFFECT_REGEX.test(unHighlightEffect),
        fillColor = hasColor ? seriescolor : TRANSPARENT,
        styleObj = {};

    if (highlightEffect == NONE) {
        styleObj.fill = (cType_Obj.value === charttype.wordcloud && options.fillColor) || fillColor;
    } else {
        // TODO: Add code for adding gradient in patternStyles
        const patternStyles = getHoverGradients(point, index, this.chart);
        patternStyles.fill = fillColor;
        patternStyles.stroke = seriescolor;
        basecolor = basecolor == 'inherit' ? seriescolor : patternStyles.fill;
        styleObj = legendH.getEffect && legendH.getEffect(highlightEffect, cType, basecolor, patternStyles, index, 'plot', point);

        if (arrayIncludes(chartcategory.nonAxisSingleSourceEvent, cType_Obj.value)) {
            styleObj = {
                fill: hasColor || cType_Obj.value === charttype.wordcloud ? options.fillColor : TRANSPARENT,
                stroke: options.strokeColor,
                ...styleObj
            };
        }
    }
    return styleObj;
}
